bind.calculate:
if( /pregnancy/previous_rchcard_status ="true", 
  /pregnancy/client_EDD_c , 
 if( /pregnancy/hide_lmp_or_months_pregnant ="true",
 if(selected( /pregnancy/rch_card/is_delivery_date_written ,"yes"), 
  /pregnancy/rch_card/estimated_delivery_date_input ,
  /pregnancy/client_EDD_c ), 
 if(selected( /pregnancy/rch_card/is_delivery_date_written ,"yes"), 
  /pregnancy/rch_card/estimated_delivery_date_input ,
 if(selected( /pregnancy/rch_card/remember_lmp ,'yes'),
 format-date(decimal-date-time( /pregnancy/rch_card/last_lmp_date ) + 40* /pregnancy/week , "%Y-%m-%d"),
 if( /pregnancy/rch_card/estimated_months_pregnant  != "",
 format-date(decimal-date-time(today())+ ((40 -  /pregnancy/rch_card/estimated_months_pregnant *4.5 )* /pregnancy/week ), "%Y-%m-%d"),"")))))
